import { Completion, CompletionContext, CompletionResult } from '@codemirror/autocomplete';
import { type ReactElement } from 'react';
/**
 * @internal
 */
export type AutocompleteProvider = (context: CompletionContext) => Promise<AutocompletionResult | null>;
/**
 * @internal
 */
export interface AutocompletionResult extends Omit<CompletionResult, 'options'> {
    suggestions: Suggestion[];
    /** @defaultValue false */
    reopen?: boolean | ((suggestions: Completion) => Promise<boolean>);
    keepOrder?: boolean;
}
/**
 * @internal
 */
export interface Suggestion extends Pick<Completion, 'label' | 'apply' | 'boost' | 'section'> {
    prefix?: (({ suggestion }: {
        suggestion: Suggestion;
    }) => ReactElement) | string;
    postfix?: (({ suggestion }: {
        suggestion: Suggestion;
    }) => ReactElement) | string;
    popup?: ({ suggestion }: {
        suggestion: Suggestion;
    }) => ReactElement;
    type?: string;
}
